/***************
 * APPROVAL CHANGE (Option A behavior)
 ***************/
function handleApprovalChange(sheet, row) {
  const lastCol   = Math.max(sheet.getLastColumn(), COL_ARRIVAL_DATE);
  const rowValues = sheet.getRange(row, 1, 1, lastCol).getValues()[0] || [];

  const statusRaw      = String(rowValues[COL_APPROVAL_STATUS - 1] || '').trim();
  const currentRouting = String(rowValues[COL_ORDER_ROUTING - 1] || '').trim();
  const totalCost      = Number(rowValues[COL_TOTAL_COST - 1]) || 0;
  const grade          = String(rowValues[COL_GRADE - 1] || '').trim();
  const now            = new Date();
  const ts             = Utilities.formatDate(now, Session.getScriptTimeZone(), 'M/d/yyyy h:mma');
  const reviewerName   = currentRouting || 'Reviewer';

  if (!statusRaw) return;

  const normalized = statusRaw.toLowerCase();

  if (
    normalized.startsWith('approved by ') ||
    normalized.startsWith('approved (override) by ') ||
    normalized.startsWith('denied by ') ||
    normalized.startsWith('ordered by ')
  ) {
    return;
  }

  if (normalized === 'approved' ||
      normalized === 'denied' ||
      normalized === 'approved (override)') {
    sheet.getRange(row, COL_APPROVED_DATE).setValue(now);
  }

  if (normalized === 'approved (override)') {
    processOverrideApproval(sheet, row, rowValues);
    return;
  }

  if (normalized === 'denied') {
    var deniedText = 'Denied by ' + reviewerName + ' on ' + ts;
    sheet.getRange(row, COL_APPROVAL_STATUS).setValue(deniedText);
    sheet.getRange(row, COL_ORDER_ROUTING).setValue('Complete');
    appendHistory(sheet, row, 'Denied by ' + reviewerName);
    return;
  }

  if (normalized === 'approved') {

    if (totalCost <= 0) {
      sheet.getRange(row, COL_APPROVAL_STATUS).setValue('Pending');
      appendHistory(sheet, row, 'Approval reset to Pending — total cost is $0');
      return;
    }

    var gradeGroup = mapGradeToGroup(grade);
    if (!gradeGroup) {
      appendHistory(sheet, row, 'Approval failed — grade "' + grade + '" not recognized');
      return;
    }

    var classCap  = lookupClassCap(grade);
    var classUsed = calculateClassUsed(sheet, grade);

    if (classCap && (classUsed + totalCost > classCap)) {
      var capText = 'Denied by ' + reviewerName + ' on ' + ts + ' — Class cap exceeded';
      sheet.getRange(row, COL_APPROVAL_STATUS).setValue(capText);
      appendHistory(sheet, row, 'Denied — Class cap exceeded');
      return;
    }

    if (!canAffordFromGradeGroup(gradeGroup, totalCost)) {
      var budgetText = 'Denied by ' + reviewerName + ' on ' + ts + ' — Grade group budget exceeded';
      sheet.getRange(row, COL_APPROVAL_STATUS).setValue(budgetText);
      appendHistory(sheet, row, 'Denied — Grade group budget exceeded');
      return;
    }

    updateBudget(gradeGroup, totalCost);

    var approvedText = 'Approved by ' + reviewerName + ' on ' + ts;
    sheet.getRange(row, COL_APPROVAL_STATUS).setValue(approvedText);
    appendHistory(sheet, row, 'Approved by ' + reviewerName);

    if (currentRouting && currentRouting !== ADMIN_NAME) {
      sheet.getRange(row, COL_ORDER_ROUTING).setValue(ADMIN_NAME);
      appendHistory(sheet, row, 'Routed to ' + ADMIN_NAME + ' for ordering');
      sendAdminEmail({
        to: ADMIN_EMAIL,
        sheetName: sheet.getName(),
        rowValues: rowValues
      });
    }
  }
}


function handleApprovalChange2(sheet, row) {
  // OPTIONAL: lock if budgets/history are shared resources
  // const lock = LockService.getScriptLock();
  // lock.waitLock(30000); // [4](https://stackoverflow.com/questions/43223774/how-to-understand-lockservice-and-implement-it-correctly)

  const lastCol = Math.max(sheet.getLastColumn(), COL_ARRIVAL_DATE);
  const rowRange = sheet.getRange(row, 1, 1, lastCol);
  const rowValues2D = rowRange.getValues();         // single read [2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
  const rowValues = (rowValues2D[0] || []);

  const statusRaw      = String(rowValues[COL_APPROVAL_STATUS - 1] || '').trim();
  if (!statusRaw) return;

  const normalized = statusRaw.toLowerCase();

  // Already processed? Exit
  if (
    normalized.startsWith('approved by ') ||
    normalized.startsWith('approved (override) by ') ||
    normalized.startsWith('denied by ') ||
    normalized.startsWith('ordered by ')
  ) return;

  const currentRouting = String(rowValues[COL_ORDER_ROUTING - 1] || '').trim();
  const totalCost      = Number(rowValues[COL_TOTAL_COST - 1]) || 0;
  const grade          = String(rowValues[COL_GRADE - 1] || '').trim();

  const now = new Date();
  const ts = Utilities.formatDate(now, Session.getScriptTimeZone(), 'M/d/yyyy h:mma');
  const reviewerName = currentRouting || 'Reviewer';

  // We'll stage changes into a copy of the row, then write once
  const out = rowValues.slice();

  // set approved date for terminal statuses
  if (normalized === 'approved' || normalized === 'denied' || normalized === 'approved (override)') {
    out[COL_APPROVED_DATE - 1] = now;
  }

  if (normalized === 'approved (override)') {
    // Write staged changes first (approved date), then run override logic
    rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
    processOverrideApproval(sheet, row, rowValues); // assumes it does its own writes
    return;
  }

  if (normalized === 'denied') {
    out[COL_APPROVAL_STATUS - 1] = `Denied by ${reviewerName} on ${ts}`;
    out[COL_ORDER_ROUTING  - 1] = 'Complete';

    rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
    appendHistory(sheet, row, `Denied by ${reviewerName}`);
    return;
  }

  if (normalized === 'approved') {

    if (totalCost <= 0) {
      out[COL_APPROVAL_STATUS - 1] = 'Pending';
      rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
      appendHistory(sheet, row, 'Approval reset to Pending — total cost is $0');
      return;
    }

    const gradeGroup = mapGradeToGroup(grade);
    if (!gradeGroup) {
      appendHistory(sheet, row, `Approval failed — grade "${grade}" not recognized`);
      return;
    }

    const classCap  = lookupClassCap(grade);
    const classUsed = calculateClassUsed(sheet, grade);

    if (classCap && (classUsed + totalCost > classCap)) {
      out[COL_APPROVAL_STATUS - 1] =
        `Denied by ${reviewerName} on ${ts} — Class cap exceeded`;

      rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
      appendHistory(sheet, row, 'Denied — Class cap exceeded');
      return;
    }

    if (!canAffordFromGradeGroup(gradeGroup, totalCost)) {
      out[COL_APPROVAL_STATUS - 1] =
        `Denied by ${reviewerName} on ${ts} — Grade group budget exceeded`;

      rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
      appendHistory(sheet, row, 'Denied — Grade group budget exceeded');
      return;
    }

    // At this point, approval is valid
    updateBudget(gradeGroup, totalCost);

    out[COL_APPROVAL_STATUS - 1] = `Approved by ${reviewerName} on ${ts}`;
    rowRange.setValues([out]); // single write [1](https://developers.google.com/apps-script/guides/support/best-practices)[2](https://spreadsheet.dev/reading-from-writing-to-range-in-google-sheets-using-apps-script)
    appendHistory(sheet, row, `Approved by ${reviewerName}`);

    if (currentRouting && currentRouting !== ADMIN_NAME) {
      // This is a second update; you can also stage it into the same write
      sheet.getRange(row, COL_ORDER_ROUTING).setValue(ADMIN_NAME);
      appendHistory(sheet, row, `Routed to ${ADMIN_NAME} for ordering`);
      sendAdminEmail({
        to: ADMIN_EMAIL,
        sheetName: sheet.getName(),
        rowValues: rowValues
      });
    }
  }

  // OPTIONAL: lock.releaseLock();
}
